class Solution:
    def binaryGap(self, n: int) -> int:
        last_one = -1
        max_gap = 0
        i = 0
        while n:
            if n & 1:
                if last_one != -1:
                    max_gap = max(max_gap, i - last_one)
                last_one = i
            n >>= 1
            i += 1
        return max_gap
